  ('locality-6f0ba476-moex-00197', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於 7 月 31 日核對公司帳簿與銀行對帳單時，發現下列各事項：①公司帳上的餘額', '["託收票據，銀行已完成收款，票面金額為$27,600，利息收入為$88；", "未兌現支 票為$17,420；", "銀行之帳戶管理費為$800；⑤NSF為$25,000；⑥#5566支票之金額為$2,785， 公司帳上誤記為$2,758。試問7月31日之正確銀行存款金額應為何？", "$13,315"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00198', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司對於應收帳款減損之評估採單一損失率法，已知02年初應收帳款餘額為$750,000，備抵 損失貸餘$25,000。若當年度銷貨金額為$2,300,000，其中現銷$600,000，而帳款亦陸續收現總計 為$1,525,000。02年4月乙客戶之帳款$22,000因確定無法收現而予以沖銷。且02年5月收回丙 公司業已沖銷之帳款$10,000。請試算該公司02年度估計提列之預期信用減損損失為何？', '["$2,090", "$2,390", "$14,090", "$14,390"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00199', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '丙公司X4年度銷貨總額為$2,000,000。丙公司X4年12月31日調整前應收帳款餘額為$500,000， 備抵呆帳貸餘$26,000。X4年12月31日應收帳款的帳齡分析如下： 帳 齡 金 額 可能收回機率 15天以內 $250,000 0.96 16～30天 85,000 0.92 31～45天 65,000 0.88 46～60天 ？ 0.78 61～90天 25,000 0.52 超過90天 20,000 0.00 $500,000 丙公司若使用帳齡分析法提列呆帳，X4年12月31日應收帳款淨額為何？', '["$431,300", "$451,300", "$454,000", "$500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00200', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司X1年開始營業，對存貨評價方法採用先進先出法，X2年中，甲公司決定改採加權平 均法。先進先出法下的銷貨成本：X1年為$165,000、X2年為$200,000。加權平均法下的銷貨 成本：X1年為$158,000、X2年為$175,000。在存貨評價使用先進先出法下，甲公司X1年、 X2年淨利分別為$405,000、$360,000。甲公司在改採加權平均法下，X2年淨利為何？', '["$430,000", "$412,000", "$385,000", "$335,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00201', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司X2年至X4年帳列稅前淨利分別為$78,000、$120,000及$160,000，X5年初經會計師查 核發現X2年至X4年底各有寄銷於別家公司之商品$40,000、$60,000及$20,000未計入期末存貨 （其中，存貨採定期盤存制）。請試算甲公司X3、X4年正確之稅前淨利分別為何？', '["$60,000，$140,000", "$100,000，$200,000", "$140,000，$120,000", "$180,000，$180,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00202', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '丁公司倉庫於X5年7月1日發生火災，除了FOB起運點交貨之在途進貨外，倉庫內剩餘存 貨的估計殘值為$9,500。該批在途進貨購價為$65,000，運費$2,500已經入帳。丁公司存貨相 關資料如下：X5年1月1日存貨$64,000，1月1日至7月1日間的進貨$408,000，1月1日 至7月1日間的現金銷貨$200,000，賒銷為$300,000，進貨退回及折讓$5,000，銷貨退回$20,000， 進貨運費$2,800，銷貨運費$4,500，平均毛利率為銷貨淨額之28%。丁公司的存貨火災損失金 額為何？', '["$32,800", "$44,400", "$47,200", "$49,700"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00203', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '乙公司存貨使用定期盤存制度，X1年9月份的期初存貨共2,200單位，單位成本$18，X1年 9月份進貨與銷貨資料如下： 9月05日 進貨300單位，每單位成本$22 9月10日 銷貨550單位，每單位售價$38 9月13日 銷貨450單位，每單位售價$40 9月25日 進貨500單位，每單位成本$20 乙公司使用成本與淨變現價值孰低法來評價存貨，每單位存貨於X1年9月底的淨變現價值 為$19.5。在加權平均法下，乙公司X1年9月底之存貨金額為何？', '["$36,000", "$37,460", "$39,000", "$40,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00204', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於第 1 年初進口一台光療機，相關成本含有機器購價$1,800,000、海關關稅$25,000、 運費$80,000、運送過程損壞之修理費$50,000以及機器試運成本$18,000。此機器預估耐用年 限為 8 年，估計殘值為$5,000，採用直線法提列折舊。至第 5 年初時發現該機器尚可使用 5 年，且估計殘值為$2,000，公司並決定剩餘年限改採倍數餘額遞減法提列折舊。甲公司於第5 年提列的折舊費用應為多少？', '["$384,800", "$385,600", "$392,800", "$393,600"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "d55753a3604a", "answer_pdf_sha1": "0a51dc74764a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
